const results = $.steps.webSearch.response.results || [];
let sourcesText = '';
results.forEach((r, i) => {
  sourcesText += (i + 1) + '. ' + (r.title || 'Untitled') + '\n';
  sourcesText += '   URL: ' + r.url + '\n';
  sourcesText += '   ' + (r.text || '').slice(0, 1000) + '\n\n';
});
return { sourcesText, sourceCount: results.length, topSources: results.slice(0, 3).map(r => ({ title: r.title || r.url, url: r.url })) };

const question = $.input.question;
const history = $.input.conversationHistory || '';
const personality = $.input.personality || 'helpful and friendly';
const sources = $.steps.compileSources.output;

let prompt = 'You are a conversational AI agent. Your personality is: ' + personality + '.\n\n';

if (history) {
  prompt += 'PREVIOUS CONVERSATION:\n' + history + '\n\n';
}

prompt += 'CURRENT QUESTION: ' + question + '\n\n';

if (sources.sourceCount > 0) {
  prompt += 'WEB CONTEXT (' + sources.sourceCount + ' sources):\n' + sources.sourcesText + '\n\n';
}

prompt += 'INSTRUCTIONS:\n';
prompt += '- Respond conversationally, maintaining your personality\n';
prompt += '- Use web sources to ground your response in facts when relevant\n';
prompt += '- Cite sources naturally, e.g. [1]\n';
prompt += '- If the question is casual or personal, respond naturally without forcing sources\n';
prompt += '- Ask a follow-up question to keep the conversation going\n';
prompt += '- Use Slack mrkdwn: *bold*, _italic_, numbered lists\n';
prompt += '- Slack rules: use *bold* (NOT **bold**). No markdown tables. No # headings.\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "response": "<conversational response in Slack mrkdwn>",\n';
prompt += '  "followUpQuestion": "<a natural follow-up question>",\n';
prompt += '  "topicCategory": "<category of the question>",\n';
prompt += '  "usedSources": true,\n';
prompt += '  "mood": "informative|casual|technical|creative"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { response: raw, followUpQuestion: '', topicCategory: 'general', usedSources: false, mood: 'informative' }; }

const ai = $.steps.parseAI.output;
const question = $.input.question;
const topSources = $.steps.compileSources.output.topSources || [];

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'AI Conversational Agent' } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*You asked:* ' + question } });
blocks.push({ type: 'divider' });

const responseText = (ai.response || 'No response.').slice(0, 2900);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: responseText } });

if (ai.followUpQuestion) {
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ':speech_balloon: *Follow-up:* ' + ai.followUpQuestion } });
}

if (ai.usedSources && topSources.length > 0) {
  blocks.push({ type: 'divider' });
  let srcText = '*Sources:*\n';
  topSources.slice(0, 3).forEach((s, i) => { srcText += (i + 1) + '. <' + s.url + '|' + (s.title || s.url).slice(0, 60) + '>\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: srcText } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Topic: *' + (ai.topicCategory || 'general') + '* | Mood: *' + (ai.mood || 'informative') + '*' }] });

const fallback = 'AI Agent response to: ' + question;
return { blocks, fallback };
